class Solution:
    def kConcatenationMaxSum(self, arr, k):
        MOD = 10**9 + 7
        def kadane(seq):
            best = 0
            cur = 0
            for x in seq:
                cur = max(0, cur + x)
                best = max(best, cur)
            return best
        total = sum(arr)
        if k == 1:
            return kadane(arr) % MOD
        two = kadane(arr + arr)
        if total > 0:
            two += (k - 2) * total
        return two % MOD

