var kConcatenationMaxSum = function(arr, k) {
    const MOD = 1000000007n;
    const kadane = seq => {
        let best = 0n, cur = 0n;
        for (const x of seq) {
            cur = cur + BigInt(x);
            if (cur < 0n) cur = 0n;
            if (cur > best) best = cur;
        }
        return best;
    };
    let total = 0n;
    for (const x of arr) total += BigInt(x);
    if (k === 1) return Number(kadane(arr) % MOD);
    let two = kadane(arr.concat(arr));
    if (total > 0n) two += BigInt(k - 2) * total;
    return Number(((two % MOD) + MOD) % MOD);
};
